const keywords=require("./keywords"),escapeHtml=require("./escapeHtml"),DEFAULT_OPTIONS={html:!1,htmlEscaper:escapeHtml,classPrefix:"sql-hl-",colors:{keyword:"\x1B[35m",function:"\x1B[31m",number:"\x1B[32m",string:"\x1B[32m",identifier:"\x1B[0m",special:"\x1B[33m",bracket:"\x1B[33m",comment:"\x1B[2m\x1B[90m",clear:"\x1B[0m"}},highlighters=[/(?<number>[+-]?(?:\d+\.\d+|\d+|\.\d+)(?:E[+-]?\d+)?)/,/(?<string>'(?:[^'\\]|\\.)*'|"(?:[^"\\]|\\.)*")/,/(?<comment>--[^\n\r]*|#[^\n\r]*|\/\*(?:[^*]|\*(?!\/))*\*\/)/,/\b(?<function>\w+)(?=\s*\()/,/(?<bracket>[()])/,/(?<identifier>\b\w+\b|`(?:[^`\\]|\\.)*`)/,/(?<whitespace>\s+)/,/(?<special>\^-=|\|\*=|\+=|-=|\*=|\/=|%=|&=|>=|<=|<>|!=|!<|!>|>>|<<|.)/],tokenizer=new RegExp([`\\b(?<keyword>${keywords.join("|")})\\b`,...highlighters.map(r=>r.source)].join("|"),"gis");function getSegments(r){return Array.from(r.matchAll(tokenizer),e=>({name:Object.keys(e.groups).find(s=>e.groups[s]),content:e[0]}))}function highlight(r,n){const e=Object.assign({},DEFAULT_OPTIONS,n);return getSegments(r).map(({name:s,content:t})=>{if(e.html){const o=e.htmlEscaper(t);return s==="whitespace"?o:`<span class="${e.classPrefix}${s}">${o}</span>`}return e.colors[s]?e.colors[s]+t+e.colors.clear:t}).join("")}module.exports={getSegments,highlight,DEFAULT_OPTIONS};
